1	import type { HookBus } from './hook-bus.js';
2	import { PluginError } from './errors.js';
3	import { PluginManifestSchema, type Plugin } from './plugin.js';
4	
5	export interface BootstrapOptions {
6	  bus: HookBus;
7	  plugins: Plugin[];
8	  config: Record<string, unknown>;
9	}
10	
11	export async function bootstrap(opts: BootstrapOptions): Promise<void> {
12	  const { bus, plugins, config } = opts;
13	
14	  for (const p of plugins) {
15	    const parsed = PluginManifestSchema.safeParse(p.manifest);
16	    if (!parsed.success) {
17	      throw new PluginError({
18	        code: 'invalid-manifest',
19	        plugin: p.manifest?.name ?? 'unknown',
20	        message: `invalid plugin manifest: ${parsed.error.message}`,
21	        cause: parsed.error,
22	      });
23	    }
24	  }
25	
26	  detectCycles(plugins);
27	
28	  for (const p of plugins) {
29	    try {
30	      await p.init({ bus, config: (config as Record<string, unknown>)[p.manifest.name] });
31	    } catch (err) {
32	      if (err instanceof PluginError) throw err;
33	      throw new PluginError({
34	        code: 'init-failed',
35	        plugin: p.manifest.name,
36	        message: `plugin '${p.manifest.name}' init failed: ${err instanceof Error ? err.message : String(err)}`,
37	        cause: err,
38	      });
39	    }
40	  }
41	
42	  verifyCalls(plugins, bus);
43	}
44	
45	function detectCycles(plugins: Plugin[]): void {
46	  const producers = new Map<string, string>();
47	  for (const p of plugins) {
48	    for (const r of p.manifest.registers) {
49	      const existing = producers.get(r);
50	      if (existing !== undefined && existing !== p.manifest.name) {
51	        throw new PluginError({
52	          code: 'duplicate-service',
53	          plugin: p.manifest.name,
54	          message: `service hook '${r}' registered by both '${existing}' and '${p.manifest.name}'`,
55	        });
56	      }
57	      producers.set(r, p.manifest.name);
58	    }
59	  }
60	
61	  const graph = new Map<string, string[]>();
62	  for (const p of plugins) {
63	    const out: string[] = [];
64	    for (const c of p.manifest.calls) {
65	      const prod = producers.get(c);
66	      if (prod !== undefined && prod !== p.manifest.name) out.push(prod);
67	    }
68	    graph.set(p.manifest.name, out);
69	  }
70	
71	  const visiting = new Set<string>();
72	  const done = new Set<string>();
73	
74	  const visit = (node: string, stack: string[]): void => {
75	    if (done.has(node)) return;
76	    if (visiting.has(node)) {
77	      const cycleStart = stack.indexOf(node);
78	      const cycle = stack.slice(cycleStart).concat(node).join(' → ');
79	      throw new PluginError({
80	        code: 'cycle',
81	        plugin: node,
82	        message: `plugin call cycle detected: ${cycle}`,
83	      });
84	    }
85	    visiting.add(node);
86	    for (const next of graph.get(node) ?? []) {
87	      visit(next, [...stack, node]);
88	    }
89	    visiting.delete(node);
90	    done.add(node);
91	  };
92	
93	  for (const name of graph.keys()) visit(name, []);
94	}
95	
96	function verifyCalls(plugins: Plugin[], bus: HookBus): void {
97	  for (const p of plugins) {
98	    for (const hook of p.manifest.calls) {
99	      if (!bus.hasService(hook)) {
100	        throw new PluginError({
101	          code: 'missing-service',
102	          plugin: p.manifest.name,
103	          message: `plugin '${p.manifest.name}' declares calls:['${hook}'] but no plugin registers it`,
104	        });
105	      }
106	    }
107	  }
108	}
