export interface PluginErrorOptions {
  code: PluginErrorCode;
  plugin: string;
  message: string;
  cause?: unknown;
}

export class PluginError extends Error {
  readonly code: PluginErrorCode;
  readonly plugin: string;

  constructor(opts: PluginErrorOptions) {
