        return await terminate(bus, ctx, `llm:pre-call:${pre.reason}`);
      }

      const response = await bus.call<LlmRequest, LlmResponse>('llm:call', ctx, pre.payload);

      const post = await bus.fire<LlmResponse>('llm:post-call', ctx, response);
      if (post.rejected) {
